// src/pages/admin/AdminDashboard.js
import React, { useEffect, useState } from "react";
import {
  getOverview,
  getUsers,
  getApprovedCaptains,
  getPendingCaptains,
  getRides,
  approveCaptain,
  rejectCaptain,
} from "../../services/adminApi";
import { useAuth } from "../../contexts/AuthContext";
import {
  AppBar,
  Toolbar,
  Box,
  Typography,
  Button,
  CircularProgress,
  Table,
  TableHead,
  TableBody,
  TableRow,
  TableCell,
  Card,
  CardContent,
  Grid,
  Paper,
  Link,
  Stack,
  Tabs,
  Tab,
  Divider,
} from "@mui/material";

// New Icons for professional look
import AccountCircleIcon from "@mui/icons-material/AccountCircle";
import VerifiedUserIcon from "@mui/icons-material/VerifiedUser";
import HourglassEmptyIcon from "@mui/icons-material/HourglassEmpty";
import DirectionsCarIcon from "@mui/icons-material/DirectionsCar";
import ThumbUpIcon from "@mui/icons-material/ThumbUp";
import ThumbDownIcon from "@mui/icons-material/ThumbDown";

export default function AdminDashboard() {
  const { logout } = useAuth();

  const [overview, setOverview] = useState({
    users: 0,
    captains: 0,
    pendingCaptains: 0,
    rides: 0,
  });

  const [activeTab, setActiveTab] = useState("overview");
  const [data, setData] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  // Fetch overview counts
  const fetchOverview = async () => {
    try {
      const res = await getOverview();
      setOverview(res.data.data);
    } catch (err) {
      console.error(err);
      setError("Failed to load overview");
    }
  };

  // Fetch table data based on tab
  const fetchData = async (type) => {
    setActiveTab(type);
    setLoading(true);
    setError("");
    try {
      let res;
      switch (type) {
        case "users":
          res = await getUsers();
          break;
        case "captains":
          res = await getApprovedCaptains();
          break;
        case "pending":
          res = await getPendingCaptains();
          break;
        case "rides":
          res = await getRides();
          break;
        default:
          res = { data: { data: [] } };
      }
      setData(res?.data?.data || []);
    } catch (err) {
      console.error(err);
      setError("Failed to fetch data");
      setData([]);
    } finally {
      setLoading(false);
    }
  };

  // Approve captain
  const handleApprove = async (id) => {
    try {
      await approveCaptain(id);
      fetchData("pending");
      fetchOverview();
    } catch (err) {
      console.error(err);
      setError("Failed to approve captain");
    }
  };

  // Reject captain
  const handleReject = async (id) => {
    try {
      await rejectCaptain(id);
      fetchData("pending");
      fetchOverview();
    } catch (err) {
      console.error(err);
      setError("Failed to reject captain");
    }
  };

  useEffect(() => {
    fetchOverview();
  }, []);

  // Dashboard cards
  const cards = [
    { label: "Users", value: overview.users, icon: <AccountCircleIcon fontSize="large" />, type: "users", color: "#1976d2" },
    { label: "Approved Captains", value: overview.captains, icon: <VerifiedUserIcon fontSize="large" />, type: "captains", color: "#388e3c" },
    { label: "Pending Captains", value: overview.pendingCaptains, icon: <HourglassEmptyIcon fontSize="large" />, type: "pending", color: "#f57c00" },
    { label: "Rides", value: overview.rides, icon: <DirectionsCarIcon fontSize="large" />, type: "rides", color: "#7b1fa2" },
  ];

  // Tab click handler
  const handleTabChange = (event, newValue) => {
    if (newValue === "overview") {
      setActiveTab("overview");
      setData([]);
    } else {
      fetchData(newValue);
    }
  };

  return (
    <Box sx={{ minHeight: "100vh", bgcolor: "#f0f2f5" }}>
      {/* Header */}
      <AppBar position="static" sx={{ bgcolor: "#0d47a1" }}>
        <Toolbar sx={{ display: "flex", justifyContent: "space-between" }}>
          <Typography variant="h6" fontWeight="bold">
            Rider App - Admin
          </Typography>
          <Button variant="contained" color="error" onClick={logout}>
            Logout
          </Button>
        </Toolbar>
      </AppBar>

      <Box sx={{ maxWidth: 1200, mx: "auto", px: 3, py: 4 }}>
        {/* Tabs */}
        <Tabs value={activeTab} onChange={handleTabChange} sx={{ mb: 3 }}>
          <Tab label="Overview" value="overview" />
          <Tab label="Users" value="users" />
          <Tab label="Approved Captains" value="captains" />
          <Tab label="Pending Captains" value="pending" />
          <Tab label="Rides" value="rides" />
        </Tabs>

        {/* Overview cards */}
        {activeTab === "overview" && (
          <Grid container spacing={3} mb={4} justifyContent="center">
            {cards.map((card) => (
              <Grid item xs={12} sm={6} md={3} key={card.label}>
                <Card
                  sx={{
                    textAlign: "center",
                    cursor: "pointer",
                    borderRadius: 3,
                    boxShadow: 3,
                    transition: "0.3s",
                    "&:hover": { boxShadow: 6, transform: "translateY(-4px)" },
                    p: 3,
                    bgcolor: card.color,
                    color: "#fff",
                  }}
                  onClick={() => fetchData(card.type)}
                >
                  <Box mb={1}>{card.icon}</Box>
                  <Typography variant="subtitle1" fontWeight="bold">
                    {card.label}
                  </Typography>
                  <Typography variant="h4" fontWeight="bold">
                    {card.value}
                  </Typography>
                </Card>
              </Grid>
            ))}
          </Grid>
        )}

        <Divider sx={{ mb: 4 }} />

        {/* Loading / Error */}
        {loading && (
          <Box display="flex" justifyContent="center" mt={4}>
            <CircularProgress />
          </Box>
        )}
        {error && (
          <Typography color="error" textAlign="center" mt={2}>
            {error}
          </Typography>
        )}

        {/* Table */}
        {!loading && data.length > 0 && (
          <Paper sx={{ p: 3, borderRadius: 3, boxShadow: 3 }}>
            <Typography variant="h6" mb={2} fontWeight="bold">
              {activeTab.charAt(0).toUpperCase() + activeTab.slice(1)} Details
            </Typography>
            <Table>
              <TableHead>
                <TableRow>
                  <TableCell>Name</TableCell>
                  <TableCell>Email</TableCell>
                  <TableCell>Mobile</TableCell>
                  <TableCell>Role</TableCell>
                  {(activeTab === "captains" || activeTab === "pending") && <TableCell>Documents</TableCell>}
                  {activeTab === "pending" && <TableCell align="center">Actions</TableCell>}
                  {activeTab === "rides" && (
                    <>
                      <TableCell>Captain</TableCell>
                      <TableCell>Pickup</TableCell>
                      <TableCell>Drop</TableCell>
                      <TableCell>Status</TableCell>
                    </>
                  )}
                </TableRow>
              </TableHead>
              <TableBody>
                {data.map((item) => (
                  <TableRow key={item._id}>
                    <TableCell>{item.fullName || "-"}</TableCell>
                    <TableCell>{item.email || "-"}</TableCell>
                    <TableCell>{item.mobile || "-"}</TableCell>
                    <TableCell>{item.role || "-"}</TableCell>

                    {(activeTab === "captains" || activeTab === "pending") && (
                      <TableCell>
                        {item.documents?.length > 0 ? (
                          item.documents.map((doc, idx) => (
                            <Box key={idx}>
                              <Link href={doc.url} target="_blank" rel="noopener">
                                {doc.name || `Document ${idx + 1}`}
                              </Link>
                            </Box>
                          ))
                        ) : (
                          "-"
                        )}
                      </TableCell>
                    )}

                    {activeTab === "pending" && (
                      <TableCell align="center">
                        <Stack direction="row" spacing={1} justifyContent="center">
                          <Button
                            size="small"
                            color="success"
                            variant="outlined"
                            startIcon={<ThumbUpIcon />}
                            onClick={() => handleApprove(item._id)}
                          >
                            Approve
                          </Button>
                          <Button
                            size="small"
                            color="error"
                            variant="outlined"
                            startIcon={<ThumbDownIcon />}
                            onClick={() => handleReject(item._id)}
                          >
                            Reject
                          </Button>
                        </Stack>
                      </TableCell>
                    )}

                    {activeTab === "rides" && (
                      <>
                        <TableCell>{item.captainId?.fullName || "-"}</TableCell>
                        <TableCell>{item.pickup || "-"}</TableCell>
                        <TableCell>{item.drop || "-"}</TableCell>
                        <TableCell>{item.status || "-"}</TableCell>
                      </>
                    )}
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          </Paper>
        )}

        {/* No Data */}
        {!loading && data.length === 0 && activeTab !== "overview" && (
          <Typography textAlign="center" mt={3}>
            No data found
          </Typography>
        )}
      </Box>
    </Box>
  );
}
